import signal
import pytest

def test_bitcount_127():
    def _timeout(signum, frame):
        raise TimeoutError("bitcount stuck in infinite loop")

    signal.signal(signal.SIGALRM, _timeout)
    signal.alarm(3)
    try:
        result = source.bitcount(127)
        signal.alarm(0)
    except TimeoutError:
        pytest.fail("bitcount(127) timed out — infinite loop caused by XOR bug")
    assert result == 7
